class LiveProofComposer:
    """Composer for creating transaction groups for LiveProof contract calls"""

    def __init__(self, client: "LiveProofClient"):
        self.client = client
        self._composer = client.algorand.new_group()
        self._result_mappers: list[typing.Callable[[algokit_utils.ABIReturn | None], object] | None] = []

    def anchor_proof(
        self,
        args: tuple[str, str, str, int] | AnchorProofArgs,
        params: algokit_utils.CommonAppCallParams | None = None
    ) -> "LiveProofComposer":
        self._composer.add_app_call_method_call(
            self.client.params.anchor_proof(
                args=args,
                params=params,
            )
        )
        self._result_mappers.append(
            lambda v: self.client.decode_return_value(
                "anchor_proof(string,string,string,uint64)void", v
            )
        )
        return self

